--Q1 WHAT IS THE TOTAL REVENUE GENERATED BY MALE VS FEMALE CUSTOMERS?
	SELECT Gender, SUM(Purchase_Amount) FROM cust
	GROUP BY GENDER

--Q2 WHAT CUSTOMERS USED A DISCOUNT BU STILL SPENT MORE THAN THE AVERAGE PURCHASE AMOUNT?
		SELECT Customer_ID,Purchase_Amount FROM cust
		WHERE Discount_Applied = 'YES' AND Purchase_Amount >= (SELECT AVG(Purchase_Amount) FROM CUST)

--Q3 WHICH ARE THE TOP 5 PRODUCTS WITH THE HIGHEST AVERAGE REVIEW RATING?
		SELECT TOP 5 Item_Purchased,ROUND(AVG(REVIEW_RATING),2) AS "AVERAGE PRODUCT RATING" FROM cust
		GROUP BY Item_Purchased
		ORDER BY AVG(REVIEW_RATING) DESC

--Q4 COMPARE THE AVERAGE PURCHASE AMOUNT BETWEEN STANDARD AND EXPRESS SHIPPING
	SELECT SHIPPING_TYPE,ROUND(AVG(Purchase_Amount),2) FROM cust
	WHERE Shipping_Type IN ('STANDARD','EXPRESS')
	GROUP BY Shipping_Type

--Q5 DO SUBSRIBED CUSTOMER SPEND MORE? COMPARE AVERAGE SPEND AND TOTAL REVENUE
		SELECT Subscription_Status, COUNT(CUSTOMER_ID) AS TOTAL_CUSTOMER,ROUND(AVG(PURCHASE_AMOUNT),2) AS AVG_SPEND,
		ROUND(SUM(PURCHASE_AMOUNT),2) AS TOTALI_REVENUE FROM cust
		GROUP BY Subscription_Status
		ORDER BY TOTALI_REVENUE,AVG_SPEND DESC;

--Q6 WHICH 5 PRODUCTS HAVE THE HIGHEST PERCENTAGE OF PURCHASE WITH DISCOUNT APPILED?
		SELECT TOP 5 ITEM_PURCHASED, (SUM(CASE WHEN Discount_Applied = 'YES' THEN 1 ELSE 0 END)*100 /COUNT(*)) AS DISCOUNT_RATE 
		FROM CUST
		GROUP BY ITEM_PURCHASED
		ORDER BY DISCOUNT_RATE DESC

--Q7 SEGMENT CUSTOMERS INTO NEW,RETURING, AND LOYAL BASED ON THEIR TOAL NUMBER OF PREVIOUS PURCHASE,AND SHOW THE COUNT OF EACH SEGMENT.
	WITH CUSTOMER_TYPE AS 
	(
	SELECT CUSTOMER_ID,PREVIOUS_PURCHASES,
	CASE 
		WHEN Previous_Purchases = 1 THEN 'NEW'
		WHEN PREVIOUS_PURCHASES BETWEEN 2 AND 10 THEN 'RETURINING'
		ELSE 'LOYAL'
		END AS CUSTOMER_SEGMENT
	FROM cust
	)
	SELECT CUSTOMER_SEGMENT ,COUNT(*) AS 'NUMBER OF CUSTOMERS'
	FROM CUSTOMER_TYPE
	GROUP BY CUSTOMER_SEGMENT

--Q8 WHAT ARE THE TOP 3 MOS PURCHASED PRODUCTS WITHIN EACH CATEGORY?
	WITH ITEM_COUNTS AS (
	SELECT CATEGORY,ITEM_PURCHASED,
	COUNT(CUSTOMER_ID) AS TOTAL_ORDERS,
	ROW_NUMBER() OVER(PARTITION BY CATEGORY ORDER BY COUNT(CUSTOMER_ID) DESC) AS ITEM_RANK
	FROM CUST
	GROUP BY CATEGORY,ITEM_PURCHASED
	)
	SELECT ITEM_RANK,CATEGORY,ITEM_PURCHASED,TOTAL_ORDERS 
	FROM ITEM_COUNTS
	WHERE ITEM_RANK <= 3;

	--are customers who are repeat buyers (more than 5 previous purchases) also likely to subscribe ?
	SELECT SUBSCRIPTION_STATUS,
	COUNT(CUSTOMER_ID) AS REPEATED_BUYERS
	FROM CUST
	WHERE previous_purchases >5
	GROUP BY subscription_status
	--WHAT IS THE REVENUE BY AGE GROUP
	SELECT AGE_GROUP ,SUM (PURCHASE_AMOUNT)AS TOTAL_REVENUE
	FROM CUST
	GROUP BY AGE_GROUP
	ORDER  BY TOTAL_REVENUE DESC
